import{_ as e,o as l,c as i,ai as t}from"./chunks/framework.CaiDwmc7.js";const f=JSON.parse('{"title":"技术体系","description":"","frontmatter":{},"headers":[],"relativePath":"tech-system/index.md","filePath":"tech-system/index.md"}'),r={name:"tech-system/index.md"};function h(o,a,n,s,d,c){return l(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="技术体系" tabindex="-1">技术体系 <a class="header-anchor" href="#技术体系" aria-label="Permalink to “技术体系”">​</a></h1><p>本站“技术体系”仅面向 <strong>初级 / 中级开发</strong>，用来梳理学习路线与知识地图。偏 <strong>中高级/高级</strong> 的内容（如分布式一致性、云原生、LLM 微调、数仓/大数据、系统架构模式专题等）会暂时下线。</p><h2 id="🏗️-核心技术栈" tabindex="-1">🏗️ 核心技术栈 <a class="header-anchor" href="#🏗️-核心技术栈" aria-label="Permalink to “🏗️ 核心技术栈”">​</a></h2><h3 id="后端技术栈" tabindex="-1">后端技术栈 <a class="header-anchor" href="#后端技术栈" aria-label="Permalink to “后端技术栈”">​</a></h3><ul><li><a href="./backend/java-spring.html">Java/Spring 生态</a> - Spring Boot、常用组件、工程化</li><li><a href="./backend/python-stack.html">Python 生态</a> - Django、Flask、FastAPI</li><li><a href="./backend/nodejs-stack.html">Node.js 生态</a> - Express、NestJS</li><li><a href="./backend/golang.html">Go 语言</a> - 基础语法、并发、Web 开发</li><li><a href="./backend/iot-project.html">物联网项目学习路线</a> - 设备接入、数据上报、在线状态、可视化</li></ul><h3 id="前端技术栈" tabindex="-1">前端技术栈 <a class="header-anchor" href="#前端技术栈" aria-label="Permalink to “前端技术栈”">​</a></h3><ul><li><a href="./frontend/vue-stack.html">Vue.js 生态</a> - Vue 3、组合式API、Vuex/Pinia</li><li><a href="./frontend/react-stack.html">React 生态</a> - React 18、Hooks、Redux、Next.js</li><li><a href="./frontend/engineering.html">前端工程化</a> - Webpack、Vite、TypeScript、测试</li><li><a href="./frontend/mobile.html">移动端开发</a> - React Native、Flutter、PWA</li><li><a href="./frontend/cross-platform.html">跨平台方案</a> - Electron、Tauri、WebAssembly</li></ul><h3 id="数据库与存储" tabindex="-1">数据库与存储 <a class="header-anchor" href="#数据库与存储" aria-label="Permalink to “数据库与存储”">​</a></h3><ul><li><a href="./database/relational.html">关系型数据库</a> - MySQL、PostgreSQL优化</li><li><a href="./database/nosql.html">NoSQL 数据库</a> - MongoDB、Redis、Elasticsearch</li><li><a href="./database/caching.html">缓存系统</a> - Redis集群、缓存策略、性能优化</li></ul><blockquote><p>数仓/大数据、分布式存储等偏中高级内容，暂时下线。</p></blockquote><h2 id="🔌-系统集成与设备通信-http-工控" tabindex="-1">🔌 系统集成与设备通信（HTTP / 工控） <a class="header-anchor" href="#🔌-系统集成与设备通信-http-工控" aria-label="Permalink to “🔌 系统集成与设备通信（HTTP / 工控）”">​</a></h2><p>面向 <strong>多语言服务对接</strong> 与 <strong>PLC 数采</strong> 等场景：广义都属于「数据通信」，但 HTTP 偏 <strong>应用层 API</strong>，Modbus TCP 偏 <strong>工控设备层协议</strong>。</p><ul><li><a href="./integration/cross-language-interop.html">跨语言调用：方式选型与常见实现</a> — HTTP/gRPC/MQ/FFI/子进程等是否可行、怎么选</li><li><a href="./integration/http-node-python.html">HTTP 跨语言协作：Node.js ↔ Python</a> — REST/JSON、网关与算法服务拆分、常见 Express/axios 踩坑</li><li><a href="./integration/modbus-tcp-node-plc.html">Modbus TCP：Node.js ↔ PLC</a> — 从站、寄存器/线圈、502 端口、联调清单与安全注意</li></ul><p>可与 <a href="./backend/iot-project.html">物联网项目学习路线</a> 一起看：设备接入、上报与可视化常与上述通信方式组合使用。</p><h2 id="🚀-devops-与运维" tabindex="-1">🚀 DevOps 与运维 <a class="header-anchor" href="#🚀-devops-与运维" aria-label="Permalink to “🚀 DevOps 与运维”">​</a></h2><h3 id="容器化技术" tabindex="-1">容器化技术 <a class="header-anchor" href="#容器化技术" aria-label="Permalink to “容器化技术”">​</a></h3><ul><li><a href="./devops/docker.html">Docker 实战</a> - 镜像构建、多阶段构建、容器编排</li><li><a href="./devops/docker-desktop-windows.html">Docker Desktop Windows 配置</a> - 开机自启、容器自启、Docker Compose</li><li><a href="./devops/kubernetes.html">Kubernetes</a> - Pod管理、服务发现、配置管理</li><li><a href="./devops/container-security.html">容器安全</a> - 镜像扫描、运行时安全</li></ul><h3 id="ci-cd-流水线" tabindex="-1">CI/CD 流水线 <a class="header-anchor" href="#ci-cd-流水线" aria-label="Permalink to “CI/CD 流水线”">​</a></h3><ul><li><a href="./devops/jenkins.html">Jenkins</a> - 流水线设计、插件开发</li><li><a href="./devops/gitlab-ci.html">GitLab CI</a> - .gitlab-ci.yml、流水线优化</li><li><a href="./devops/github-actions.html">GitHub Actions</a> - 工作流设计、自托管Runner</li></ul><h3 id="监控与可观测性" tabindex="-1">监控与可观测性 <a class="header-anchor" href="#监控与可观测性" aria-label="Permalink to “监控与可观测性”">​</a></h3><ul><li><a href="./devops/monitoring.html">应用监控</a> - Prometheus、Grafana、告警规则</li><li><a href="./devops/logging.html">日志管理</a> - ELK Stack、日志聚合、分析</li><li><a href="./devops/tracing.html">链路追踪</a> - Jaeger、Zipkin、分布式追踪</li></ul><blockquote><p>云原生/Service Mesh/IaC 等偏中高级内容，暂时下线。</p></blockquote><h2 id="🛠️-开发工具与环境" tabindex="-1">🛠️ 开发工具与环境 <a class="header-anchor" href="#🛠️-开发工具与环境" aria-label="Permalink to “🛠️ 开发工具与环境”">​</a></h2><h3 id="ide-与编辑器" tabindex="-1">IDE 与编辑器 <a class="header-anchor" href="#ide-与编辑器" aria-label="Permalink to “IDE 与编辑器”">​</a></h3><ul><li><a href="./tools/vscode.html">VS Code 配置</a> - 插件推荐、设置优化、远程开发</li><li><a href="./tools/intellij.html">IntelliJ IDEA</a> - Java开发、插件生态</li><li><a href="./tools/pycharm.html">PyCharm</a> - Python开发、科学计算</li></ul><h3 id="版本控制" tabindex="-1">版本控制 <a class="header-anchor" href="#版本控制" aria-label="Permalink to “版本控制”">​</a></h3><ul><li><a href="./tools/git-workflow.html">Git 工作流</a> - 分支策略、代码审查、冲突解决</li><li><a href="./tools/github-collaboration.html">GitHub 协作</a> - PR流程、Issue管理、项目管理</li><li><a href="./tools/gitlab-enterprise.html">GitLab 企业应用</a> - CI/CD、容器注册表</li></ul><h3 id="构建与包管理" tabindex="-1">构建与包管理 <a class="header-anchor" href="#构建与包管理" aria-label="Permalink to “构建与包管理”">​</a></h3><ul><li><a href="./tools/build-tools.html">Maven/Gradle</a> - 项目构建、依赖管理、多模块</li><li><a href="./tools/package-managers.html">npm/yarn/pnpm</a> - 包管理、工作区、性能优化</li><li><a href="./tools/bundlers.html">Webpack/Vite</a> - 模块打包、优化配置</li></ul><h3 id="测试工具" tabindex="-1">测试工具 <a class="header-anchor" href="#测试工具" aria-label="Permalink to “测试工具”">​</a></h3><ul><li><a href="./tools/unit-testing.html">单元测试</a> - JUnit、pytest、Jest</li><li><a href="./tools/integration-testing.html">集成测试</a> - TestContainers、WireMock</li><li><a href="./tools/performance-testing.html">性能测试</a> - JMeter、k6、负载测试</li></ul><h2 id="📊-数据与分析" tabindex="-1">📊 数据与分析 <a class="header-anchor" href="#📊-数据与分析" aria-label="Permalink to “📊 数据与分析”">​</a></h2><h3 id="数据工程" tabindex="-1">数据工程 <a class="header-anchor" href="#数据工程" aria-label="Permalink to “数据工程”">​</a></h3><blockquote><p>数据工程/大数据方向偏中高级，暂时下线。</p></blockquote><ul><li><a href="./data/data-lake.html">数据湖</a> - 架构设计、数据治理、成本优化</li><li><a href="./data/stream-processing.html">实时数据处理</a> - Kafka Streams、Flink、Spark Streaming</li></ul><h3 id="商业智能" tabindex="-1">商业智能 <a class="header-anchor" href="#商业智能" aria-label="Permalink to “商业智能”">​</a></h3><ul><li><a href="./data/visualization.html">数据可视化</a> - Tableau、Power BI、开源替代</li><li><a href="./data/reporting.html">报表系统</a> - 动态报表、仪表板设计</li><li><a href="./data/analytics.html">数据分析</a> - SQL分析、Python分析、统计建模</li></ul><h2 id="🔒-安全与合规" tabindex="-1">🔒 安全与合规 <a class="header-anchor" href="#🔒-安全与合规" aria-label="Permalink to “🔒 安全与合规”">​</a></h2><h3 id="应用安全-初中级" tabindex="-1">应用安全（初中级） <a class="header-anchor" href="#应用安全-初中级" aria-label="Permalink to “应用安全（初中级）”">​</a></h3><ul><li><a href="./security/web-security.html">Web安全</a> - XSS、CSRF、SQL注入防护</li><li><a href="./security/security-stack.html">安全技术栈</a> - 常见安全能力地图与落地</li></ul><h2 id="📈-技术趋势与最佳实践" tabindex="-1">📈 技术趋势与最佳实践 <a class="header-anchor" href="#📈-技术趋势与最佳实践" aria-label="Permalink to “📈 技术趋势与最佳实践”">​</a></h2><h3 id="技术趋势-初中级视角" tabindex="-1">技术趋势（初中级视角） <a class="header-anchor" href="#技术趋势-初中级视角" aria-label="Permalink to “技术趋势（初中级视角）”">​</a></h3><ul><li><a href="./trends/industry-trends.html">行业趋势</a> - 常见方向与关键词</li></ul><h3 id="最佳实践" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践" aria-label="Permalink to “最佳实践”">​</a></h3><ul><li><a href="./practices/code-quality.html">代码质量</a> - 代码审查、静态分析、文档</li><li><a href="./practices/development-practices.html">研发规范</a> - 研发流程、分支策略、上线规范</li></ul><hr><p>💡 <strong>更新计划</strong>: 每个技术领域会持续更新最新内容，涵盖新版本特性、最佳实践和行业趋势。欢迎关注和投稿！</p>',47)])])}const b=e(r,[["render",h]]);export{f as __pageData,b as default};
